class ImagesController < ApplicationController
  def process_image
    image_path = "#{Rails.root}/public/images/#{params[:image_name]}"
    cmd = "convert #{image_path} -resize #{params[:width]}x#{params[:height]} #{image_path}.#{params[:format]}"
    system(cmd)
    render json: { message: 'Image processed successfully' }
  rescue StandardError => e
    render json: { error: e.message }, status: :internal_server_error
  end
end